pub fn finish_size_prefixed_acw_buffer<'a, 'b, A: ::flatbuffers::Allocator + 'a>(fbb: &'b mut ::flatbuffers::FlatBufferBuilder<'a, A>, root: ::flatbuffers::WIPOffset<ACW<'a>>) {
  fbb.finish_size_prefixed(root, Some(ACW_IDENTIFIER));
}
